sql:
SELECT COUNT(*) 
FROM visitor_demographics 
WHERE age_group = '18-24';

SELECT SUM(revenue_amount) AS total_revenue
FROM park_revenue
WHERE park_id = 1 AND year BETWEEN 2020 AND 2022;

SELECT AVG(visitors) AS average_visitors
FROM visitation_data
WHERE year = 2020;

SELECT park_id, SUM(budget_amount) AS total_budget
FROM park_budget
GROUP BY park_id;
